// Add to Student @Entity:
// enroll(Course course)
// withdraw(Course course)
// Explanation of why both sides must be updated

exercises.expected_solution:
// Added to Student @Entity:
public void enroll(Course course) {
    // Update BOTH sides:
    this.courses.add(course);       // ← student's in-memory courses set
    course.getStudents().add(this); // ← course's in-memory students set
    // Hibernate will write JOIN table based on owning side (this.courses) at flush
    // But within-session reads of course.getStudents() need immediate update
}

public void withdraw(Course course) {
    this.courses.remove(course);
    course.getStudents().remove(this);
}

// WHY BOTH SIDES MUST BE UPDATED:
// Hibernate writes to DB from the OWNING side only (Student.courses).
// But within the SAME Hibernate Session:
//   student.getCourses() reads Student.courses (in memory) → correct
//   course.getStudents() reads Course.students (in memory) → stale if not updated!
// After commit/clear, reading from DB: both sides correct.
// During a request (same session): must update both for consistency.

// Test demonstrating the fix:
public class StudentTest {
    public static void main(String[] args) {
        Student aisha = new Student("Aisha", "aisha@test.com");
        Course java = new Course("Java Programming", "CS101");

        aisha.enroll(java);  // updates BOTH sides

        // Both sides are immediately consistent:
        System.out.println(aisha.getCourses().size());    // 1 (correct)
        System.out.println(java.getStudents().size());    // 1 (correct — helper updated it)

        // WITHOUT helper (only one side):
        // aisha.getCourses().add(java);  // only Student.courses updated
        // java.getStudents().size()  → 0!  (stale — Course.students not updated)
    }
}

