@Embeddable
public class Address {
    @Column(name="street", length=200) private String street;
    @Column(name="city",   length=100) private String city;
    @Column(name="pincode",length=10)  private String pincode;
    @Column(name="state",  length=50)  private String state;
    protected Address() {}
    public Address(String street, String city, String pincode, String state) {
        this.street=street; this.city=city; this.pincode=pincode; this.state=state;
    }
    public String getCity()    { return city; }
    public String getPincode() { return pincode; }
}

@Embeddable
public class Money {
    @Column(name="amount",   precision=14, scale=2) private BigDecimal amount;
    @Column(name="currency", length=3)              private String currency = "INR";
    protected Money() {}
    public Money(BigDecimal amount)            { this.amount=amount; this.currency="INR"; }
    public Money(BigDecimal amount, String cur){ this.amount=amount; this.currency=cur; }
    public BigDecimal getAmount()  { return amount; }
    public String getCurrency()    { return currency; }
}

@Entity @Table(name="orders")
public class Order {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    private String status;

    @Embedded  // columns: street, city, pincode, state in orders table
    private Address shippingAddress;

    // Embed Money as orderTotal (column prefix: order_total_):
    @Embedded
    @AttributeOverrides({
        @AttributeOverride(name="amount",   column=@Column(name="order_total_amount")),
        @AttributeOverride(name="currency", column=@Column(name="order_total_currency"))
    })
    private Money orderTotal;

    // Embed Money again as discount (different column names):
    @Embedded
    @AttributeOverrides({
        @AttributeOverride(name="amount",   column=@Column(name="discount_amount")),
        @AttributeOverride(name="currency", column=@Column(name="discount_currency"))
    })
    private Money discount;

    protected Order() {}
    public Order(String status) { this.status=status; }
    public void setShippingAddress(Address a){ shippingAddress=a; }
    public void setOrderTotal(Money m){ orderTotal=m; }
    public void setDiscount(Money d){ discount=d; }
}

// Orders table columns:
// id, status,
// street, city, pincode, state,           ← from @Embedded Address
// order_total_amount, order_total_currency, ← from @Embedded Money (orderTotal)
// discount_amount, discount_currency        ← from @Embedded Money (discount)
// ALL in ONE table — zero JOINs for order display!

