@Entity @Table(name="products")
public class Product {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @Column(nullable=false) private String name;

    // 1. Simple String set:
    @ElementCollection
    @CollectionTable(name="product_tags",
        joinColumns=@JoinColumn(name="product_id"))
    @Column(name="tag")
    private Set<String> tags = new HashSet<>();
    // DDL: CREATE TABLE product_tags (product_id VARCHAR(36), tag VARCHAR(255),
    //        PRIMARY KEY (product_id, tag), FK(product_id) REFERENCES products)

    // 2. Ordered String list:
    @ElementCollection
    @CollectionTable(name="product_images",
        joinColumns=@JoinColumn(name="product_id"))
    @Column(name="image_url")
    @OrderColumn(name="image_index")  // maintains list order
    private List<String> imageUrls = new ArrayList<>();
    // DDL: CREATE TABLE product_images (product_id VARCHAR(36), image_url VARCHAR(500),
    //        image_index INTEGER, FK(product_id) REFERENCES products)

