    @ElementCollection
    @CollectionTable(name="product_specs",
        joinColumns=@JoinColumn(name="product_id"))
    private List<ProductSpecification> specifications = new ArrayList<>();
    // DDL: CREATE TABLE product_specs (product_id VARCHAR(36), spec_key VARCHAR(255),
    //        spec_value VARCHAR(255), FK(product_id) REFERENCES products)

    protected Product() {}
    public Product(String name) { this.name=name; }
    public Set<String> getTags()                         { return tags; }
    public List<String> getImageUrls()                   { return imageUrls; }
    public List<ProductSpecification> getSpecifications(){ return specifications; }
