import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// StudentRepository and CourseRepository assumed:
interface StudentRepository extends org.springframework.data.jpa.repository.JpaRepository<Student,String>{}
interface CourseRepository  extends org.springframework.data.jpa.repository.JpaRepository<Course,String>{}

@DataJpaTest
class StudentCourseTest {
    @Autowired TestEntityManager testEm;
    @Autowired StudentRepository studentRepo;
    @Autowired CourseRepository  courseRepo;

    Student aisha, raj;
    Course java101, python202, db301;

    @BeforeEach void setup() {
        java101  = testEm.persistAndFlush(new Course("Java Programming",  "CS101"));
        python202= testEm.persistAndFlush(new Course("Python Basics",     "CS202"));
        db301    = testEm.persistAndFlush(new Course("Database Systems",  "CS301"));

        aisha = new Student("Aisha Sharma", "aisha@test.com");
        aisha.enroll(java101);
        aisha.enroll(python202);
        aisha = studentRepo.save(aisha);

        raj = new Student("Raj Patel", "raj@test.com");
        raj.enroll(java101);
        raj = studentRepo.save(raj);

        testEm.clear();
    }

    @Test void java101_has2Students() {
        Course loaded = courseRepo.findById(java101.getId()).orElseThrow();
        // Load students association (lazy):
        assertEquals(2, loaded.getStudents().size());
    }

    @Test void aisha_has2Courses() {
        Student loaded = studentRepo.findById(aisha.getId()).orElseThrow();
        assertEquals(2, loaded.getCourses().size());
    }

    @Test void deleteAisha_coursesUnaffected() {
        studentRepo.deleteById(aisha.getId());
        testEm.flush(); testEm.clear();

        // Courses must still exist:
        assertTrue(courseRepo.existsById(java101.getId()),   "Java101 should still exist");
        assertTrue(courseRepo.existsById(python202.getId()), "Python202 should still exist");
        // Raj still enrolled in Java101:
        Student rajLoaded = studentRepo.findById(raj.getId()).orElseThrow();
        assertEquals(1, rajLoaded.getCourses().size());
    }
}

