// For each relationship, write the annotation and explain
// 1. Order → List<OrderItem>
// 2. Product → Set<Category>
// 3. User → Address
// 4. Blog → List<Comment>
// 5. Playlist → List<Song>

exercises.expected_solution:
// 1. Order → List<OrderItem> (EXCLUSIVE ownership)
// An OrderItem cannot exist without its Order.
// Removing an item from the list should delete it.
@OneToMany(cascade = CascadeType.ALL, orphanRemoval = true)
@JoinColumn(name = "order_id")
private List<OrderItem> items = new ArrayList<>();
// ✓ CascadeType.ALL: saving order saves items; deleting order deletes items
// ✓ orphanRemoval=true: order.getItems().remove(item) → DELETE FROM order_items WHERE id=?

// 2. Product → Set<Category> (SHARED reference)
// Categories are shared (Electronics used by 10,000 products).
// Deleting a product must NOT delete shared categories.
@ManyToMany(cascade = {CascadeType.PERSIST, CascadeType.MERGE})
@JoinTable(name="product_categories", ...)
private Set<Category> categories = new HashSet<>();
// ✓ cascade={PERSIST,MERGE}: saving product persists new categories
// ✗ NO orphanRemoval: would try to delete Electronics when clearing categories
// ✗ NO CascadeType.REMOVE: would delete shared categories

// 3. User → Address (EMBEDDED — not a relationship!)
// Address is a value object, not an entity.
@Embedded
private Address address;
// No cascade needed — Address is part of User's row

// 4. Blog → List<Comment> (EXCLUSIVE ownership)
// Comments exist only for their post.
@OneToMany(cascade = CascadeType.ALL, orphanRemoval = true, mappedBy = "blog")
private List<Comment> comments = new ArrayList<>();
// ✓ ALL + orphanRemoval: deleting blog cascades to all comments

// 5. Playlist → List<Song> (SHARED reference)
// Songs exist independently; multiple playlists share the same Song entity.
@ManyToMany(cascade = {CascadeType.PERSIST, CascadeType.MERGE})
@JoinTable(name="playlist_songs", ...)
private List<Song> songs = new ArrayList<>();
// ✓ PERSIST+MERGE only: removing a song from playlist ≠ deleting the song entity

public class Main { public static void main(String[] a) { System.out.println("Analysis complete"); }}

