import jakarta.persistence.*;
import org.hibernate.annotations.Where;
import org.hibernate.annotations.SQLDelete;

@Entity @Table(name="soft_orders")
@SQLDelete(sql="UPDATE soft_orders SET deleted=true WHERE id=?")
@Where(clause="deleted=false")
public class SoftOrder {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @Column(nullable=false) private String customerId;
    @Column(nullable=false) private double total;
    private boolean deleted = false;

    protected SoftOrder() {}
    public SoftOrder(String customerId, double total) {
        this.customerId=customerId; this.total=total;
    }
    public String getId()         { return id; }
    public String getCustomerId() { return customerId; }
    public boolean isDeleted()    { return deleted; }
    public void softDelete()      { this.deleted = true; }
}

interface SoftOrderRepository extends
    org.springframework.data.jpa.repository.JpaRepository<SoftOrder,String> {
    // @Where is applied automatically to findAll() and all derived queries

    @org.springframework.data.jpa.repository.Query(
        value="SELECT * FROM soft_orders WHERE id=?",
        nativeQuery=true)
    java.util.Optional<java.util.Map<String,Object>> findByIdNative(String id);
}

import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@DataJpaTest
class SoftDeleteTest {
    @Autowired SoftOrderRepository repo;
    @Autowired TestEntityManager testEm;

    @Test void findAll_excludesSoftDeleted() {
        SoftOrder o = repo.save(new SoftOrder("C001", 999.0));
        repo.deleteById(o.getId());  // @SQLDelete: UPDATE SET deleted=true, not real DELETE
        testEm.clear();
        assertEquals(0, repo.findAll().size());  // @Where: deleted=false filters it out
    }

    @Test void findById_softDeleted_returnsEmpty() {
        SoftOrder o = repo.save(new SoftOrder("C002", 599.0));
        String id = o.getId();
        repo.deleteById(id);
        testEm.clear();
        assertTrue(repo.findById(id).isEmpty());  // @Where hides it
    }

    @Test void nativeQuery_canSeeDeletedRow() {
        SoftOrder o = repo.save(new SoftOrder("C003", 299.0));
        String id = o.getId();
        repo.deleteById(id);
        testEm.clear();
        // Native query bypasses @Where:
        var row = repo.findByIdNative(id);
        assertTrue(row.isPresent(), "Row should still exist in DB after soft delete");
    }
}

