import jakarta.persistence.*;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.boot.test.autoconfigure.orm.jpa.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Import;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.LocalDateTime;
import java.util.*;

// Explicit join entity:
@Entity @Table(name="enrollments")
public class Enrollment {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="student_id") private Student2 student;
    @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="course_id")  private Course2 course;
    private LocalDateTime enrolledAt = LocalDateTime.now();
    private String grade;  // null until graded
    protected Enrollment(){}
    Enrollment(Student2 s, Course2 c){ student=s; course=c; }
    String getId(){return id;} String getGrade(){return grade;}
    void setGrade(String g){grade=g;}
    LocalDateTime getEnrolledAt(){return enrolledAt;}
}

@Entity class Student2 {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    String name;
    @OneToMany(mappedBy="student", cascade=CascadeType.ALL) List<Enrollment> enrollments=new ArrayList<>();
    protected Student2(){} Student2(String n){name=n;}
    String getId(){return id;} List<Enrollment> getEnrollments(){return enrollments;}
}

@Entity class Course2 {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    String title;
    protected Course2(){} Course2(String t){title=t;}
    String getId(){return id;} String getTitle(){return title;}
}

interface EnrollmentRepository extends JpaRepository<Enrollment,String>{}
interface Student2Repository extends JpaRepository<Student2,String>{}
interface Course2Repository  extends JpaRepository<Course2,String>{}

@Service @Transactional
class EnrollmentService {
    private final Student2Repository sr; private final Course2Repository cr;
    private final EnrollmentRepository er;
    EnrollmentService(Student2Repository sr,Course2Repository cr,EnrollmentRepository er){
        this.sr=sr;this.cr=cr;this.er=er;
    }
    Enrollment enroll(String sid, String cid){
        Student2 s=sr.findById(sid).orElseThrow();
        Course2  c=cr.findById(cid).orElseThrow();
        return er.save(new Enrollment(s,c));
    }
    void setGrade(String enrollmentId, String grade){
        Enrollment e=er.findById(enrollmentId).orElseThrow();
        e.setGrade(grade);
    }
}

@DataJpaTest @Import(EnrollmentService.class)
class EnrollmentTest {
    @Autowired EnrollmentService service;
    @Autowired Student2Repository sr; @Autowired Course2Repository cr;
    @Autowired TestEntityManager testEm;

    @Test void enroll_createsRecord(){
        Student2 s=testEm.persistAndFlush(new Student2("Aisha"));
        Course2  c=testEm.persistAndFlush(new Course2("Java 101"));
        Enrollment e=service.enroll(s.getId(),c.getId());
        assertNotNull(e.getId()); assertNotNull(e.getEnrolledAt());
