import java.util.*;

@Entity @Table(name="rp_users")
class RpUser {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    @Column(nullable=false,unique=true) String email;
    @Column(nullable=false) String name;
    @ManyToMany(cascade={CascadeType.PERSIST,CascadeType.MERGE})
    @JoinTable(name="rp_user_roles",joinColumns=@JoinColumn(name="user_id"),inverseJoinColumns=@JoinColumn(name="role_id"))
    Set<RpRole> roles=new HashSet<>();
    protected RpUser(){} RpUser(String email,String name){this.email=email;this.name=name;}
    String getId(){return id;} Set<RpRole> getRoles(){return roles;}
    void addRole(RpRole r){roles.add(r);r.getUsers().add(this);}
    void removeRole(RpRole r){roles.remove(r);r.getUsers().remove(this);}
    boolean hasRole(String roleName){return roles.stream().anyMatch(r->r.getName().equals(roleName));}
}

@Entity @Table(name="rp_roles")
class RpRole {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    @Column(nullable=false,unique=true) String name;
    String description;
    @ManyToMany(mappedBy="roles") Set<RpUser> users=new HashSet<>();
    protected RpRole(){} RpRole(String n,String d){name=n;description=d;}
    String getId(){return id;} String getName(){return name;} Set<RpUser> getUsers(){return users;}
}

interface RpUserRepository extends JpaRepository<RpUser,String>{}
interface RpRoleRepository extends JpaRepository<RpRole,String>{ Optional<RpRole> findByName(String name); }

@Service @Transactional
class UserRoleService {
    private final RpUserRepository ur; private final RpRoleRepository rr;
    UserRoleService(RpUserRepository u,RpRoleRepository r){ur=u;rr=r;}
    void assignRole(String userId,String roleName){
        RpUser u=ur.findById(userId).orElseThrow();
        RpRole r=rr.findByName(roleName).orElseThrow(()-> new IllegalArgumentException("Role not found: "+roleName));
        u.addRole(r);
    }
    void revokeRole(String userId,String roleName){
        RpUser u=ur.findById(userId).orElseThrow();
        RpRole r=rr.findByName(roleName).orElseThrow();
        u.removeRole(r);
    }
    boolean hasPermission(String userId,String roleName){
        RpUser u=ur.findById(userId).orElseThrow();
        return u.hasRole(roleName);
    }
}

@DataJpaTest @Import(UserRoleService.class)
class UserRoleTest {
    @Autowired UserRoleService svc; @Autowired RpUserRepository ur; @Autowired RpRoleRepository rr;
    @Autowired TestEntityManager testEm;
    RpUser u; RpRole admin,viewer;
    @BeforeEach void seed(){
        admin=testEm.persistAndFlush(new RpRole("ADMIN","Full access"));
        viewer=testEm.persistAndFlush(new RpRole("VIEWER","Read only"));
        u=testEm.persistAndFlush(new RpUser("aisha@rp.com","Aisha"));
        testEm.clear();
    }
    @Test void assignRole_userHasRole(){ svc.assignRole(u.getId(),"ADMIN"); assertTrue(svc.hasPermission(u.getId(),"ADMIN")); }
    @Test void revokeRole_doesNotDeleteRole(){
        svc.assignRole(u.getId(),"VIEWER"); svc.revokeRole(u.getId(),"VIEWER");
        testEm.flush(); testEm.clear();
        assertFalse(svc.hasPermission(u.getId(),"VIEWER"));
        assertTrue(rr.existsById(viewer.getId()));
    }
    @Test void hasPermission_falseForUnassigned(){ assertFalse(svc.hasPermission(u.getId(),"ADMIN")); }
}

